*change_lift

[iscript]

function setBlocksOnLiftMoving(floorWithLift, floors, x, y)
{
	// гғӘгғ•гғҲгӮ’еӢ•гҒӢгҒ—гҒҹгҒЁгҒҚгғӘгғ•гғҲгҒ®еӢ•гҒҸе…Ёгғ–гғӯгғғгӮҜгҒ®зҠ¶ж…ӢгӮ’иЁӯе®ҡгҒҷгӮӢ
	// floors гҒҜгғӘгғ•гғҲгҒҢз§»еӢ•гҒҷгӮӢгҒҷгҒ№гҒҰгҒ®йҡҺгҖӮдёҠйҡҺгҒӢгӮүй ҶгҒ«дёҰгҒ№гӮӢ

	var liftNum = floors.find(floorWithLift);	// гғӘгғ•гғҲгҒ®гҒӮгӮӢгғ•гғӯгӮўгҒ®гӮӨгғігғҮгғғгӮҜгӮ№

	for(var i = 0; i < floors.count; i++)
	{
		var p = floors[i].pos[x][y];
		if(i == liftNum)
		{
			p.n = %[type: "door", img: "marble", himg: "door"];
			p.s = %[type: "door", img: "marble", himg: "door"];
			p.w = %[type: "wall", img: "marble", himg: x == 4 ? "button" : void, button: x == 4];
			p.e = %[type: "wall", img: "marble", himg: x == 5 ? "button" : void, button: x == 5];
			p.f = %[type: "floor", img: "marble", pimg: i == 0 ? "rope5": void, info: "Elevator", icon: 69];
			if(i == 0) p.f.indoor = true;
		}
		else
		{
			p.n = %[type: "door", img: "soil", himg: "door"];
			p.s = %[type: "door", img: "soil", himg: "door"];
			p.w = %[type: "wall", img: "soil"];
			p.e = %[type: "wall", img: "soil"];
			if(i == liftNum - 1) p.f = %[type: "floor", img: "marble", pimg: i == 0 ? "rope4": "rope2"];
			// else if(i == floors.count - 1) p.f = %[type: "floor", img: "soil"];
			else if(i > liftNum) p.f = %[type: "air", trap: "air"];
			else p.f = %[type: "air", trap: "air", pimg: i == 0 ? "rope3": "rope1"];
		}
		p.f.noCount = true;	// еәҠгҒҢеёёгҒ«еӨүеҢ–гҒҷгӮӢгҒ®гҒ§ж•°гҒҲгҒӘгҒ„

		floors[i].recordChangedInfo([p.n, x, y, "n"]);
		floors[i].recordChangedInfo([p.s, x, y, "s"]);
		floors[i].recordChangedInfo([p.w, x, y, "w"]);
		floors[i].recordChangedInfo([p.e, x, y, "e"]);
		floors[i].recordChangedInfo([p.f, x, y, "f"]);
	}
}

tf.arr = [o.йүұеұұпјўпј‘, o.йүұеұұпјўпј’, o.йүұеұұпјўпј“, o.йүұеұұпјўпј”, o.йүұеұұпјўпј•];
setBlocksOnLiftMoving(o[tf.result[0]], tf.arr, 4, 4);
setBlocksOnLiftMoving(o[tf.result[1]], tf.arr, 5, 4);
delete setBlocksOnLiftMoving;

[endscript]

@elevator map=&'tf.result[game.party.curX == 4 ? 0 : 1]' lift=&'tf.result[2]'
@return
